let concept = $json.conceptInput;

// If sheet concept is empty → use Gemini output
if (!concept || concept.trim() === "") {

  const geminiItem = $items("Output the concept", 0, $itemIndex);

  if (geminiItem.length > 0) {
    concept = geminiItem[0].json.content.parts[0].text;
  }
}

return {
  json: {
    ...$json,
    conceptInput: concept
  }
};

return $items("fetch response").map(item => {
  return {
    json: {
      ...item.json,          // Keep original data
      ...item.json.images    // Extract and flatten everything inside "images"
    }
  };
});

// Get avatar data for the CURRENT row
const data = $items("Merge for concept and Avatar Data", 0, $itemIndex)?.[0]?.json || {};

const avatarNames = data["Avatar Names"] || [];
const urls = data["Reference URLs"] || [];

// Get master shot URL for the CURRENT row
const masterShotUrl = $items("Upload file", 0, $itemIndex)?.[0]?.json?.webContentLink || "";

// Build mapping
const mapping = {};
const image_urls = [];

// Add master shot at index 0
if (masterShotUrl) {
  image_urls.push(masterShotUrl);
}

// Avatar images start from index 1
avatarNames.forEach((name, index) => {
  const imageIndex = index + 1;
  mapping[name] = `<image:${imageIndex}>`;
  if (urls[index]) {
    image_urls.push(urls[index]);
  }
});

// Get fields
const storyShot = $json.StoryShots?.framePrompt || "";
const clothing = $json.ClothingDetails || "";

// Combine prompt
let combinedPrompt = `${storyShot}. Character appearance: ${clothing}`;

// Replace placeholders with image references
avatarNames.forEach((name, index) => {

  const imageIndex = index + 1;

  const placeholder1 = `<<${name}>>`;
  const placeholder2 = `<<${name.replace(/[0-9]/g,"")}>>`;

  combinedPrompt = combinedPrompt.replaceAll(placeholder1, `<image:${imageIndex}>`);
  combinedPrompt = combinedPrompt.replaceAll(placeholder2, `<image:${imageIndex}>`);

});

// Determine shot number (per shot loop)
const shot_num = $itemIndex + 1;

return {
  json: {
    ...$json,
    shot_num,
    shot_prompt: storyShot,
    kling_prompt: combinedPrompt,
    image_urls,
    mapping
  }
};

